@module generators  src=generators.lua  loc=453  sha=a77fea4  mode=namespace  self=generators

# Invariants & contracts
  @invariant  pure module, no state; a stage is fn(stream, host, params, ctx) -> { notes, delta }  @ 8
  @invariant  stream and host share one shape; stages read stream, host is the untouched original  @ 9
  @invariant  pb/ccs are absolute curves over the closed window (edge values seeded); pb val is cents  @ 11
  @invariant  ctx binds resolution, pbRangeCents, nextSameLaneNote(host), step(pitch,detune,n)  @ 12
  @invariant  periods are QN per the periodQN convention -- scalar or {num,den}  @ 13
  @invariant  mode is the stream fold -- replace overwrites the dest channel, augment adds to it  @ 16

# Shapes
  @shape  stream/host = { window={startppqL,endppqL}, chan, lane, id, notes={ {pitch,vel,detune,ppqL,endppqL},.. }, pas={ {ppqL,pitch,vel},.. }, ccs={ [cc]={ {ppqL,val,shape},.. } }, ats={ {ppqL,val},.. }, pb={ {ppqL,val,shape},.. } }  @ 10
  @shape  result = { notes = { {ppqL,endppqL,pitch,vel,detune}, ... }, delta = { {ppqL,val,shape,[tension]}, ... } }  @ 14
  @shape  kinds[kind] = { expand, mode='replace'|'augment', dest='note'|'pb'|<cc>, label, defaults, fields }  @ 15
  @shape  fxPatterns (ds project) = { [name] = { kind='notes'|'curve', lengthPpq, root?=midiPitch, specs?={ {lane=1,ppqL,endppqL,pitch,vel,detune,delay,sample?},.. }, points?={ {ppq,val,shape,tension?},.. } } }  @ 19
  @shape  parkWindows -> { {evType='note'|'cc'|'pb', chan, cc?, startppq, endppq}, ... } (cc on cc windows only)  @ 427

