# Private functions
  @fn periodTicks(period, resolution)  @ 25-28
  @fn retrig(stream, host, params, ctx)  @ 32-51
      @contract  retrig tiles the host window with evenly-spaced same-pitch fxNotes; every hit is derived  @ 30
      @contract  velocity ramps params.ramp per tile from the host vel, clamped 1..127; detune inherited verbatim  @ 31
  @fn trill(stream, host, params, ctx)  @ 54-75
      @contract  trill alternates host pitch with a note `step` scale-steps away (via ctx.step); every hit derived  @ 53
  @fn playingAt(events, t)  @ 78-87
      -- Notes sounding at logical tick `t`, ascending by realised pitch (semitone*100 + detune cents).
  @fn arpIndex(count, dir, i)  @ 91-99
      -- Which voice of the active set step `i` plays, by direction. updown bounces without
      -- repeating the extremes (span 2*(n-1)); up/down wrap.
  @fn arp(stream, host, params, ctx)  @ 104-124
      @contract  arp samples the sounding notes at each step (period QN), playing one by `dir`  @ 101
      @contract  dir up|down|updown cycles the current active set; an empty active set -> a rest  @ 102
      @contract  hits abut (endppqL = next step), clamped to the window; vel/detune from the voice  @ 103
  @fn ostinato(stream, host, params, ctx)  @ 128-149
      @contract  ostinato gates the sounding region notes by a stored pattern -- pattern gives onset/dur/vel, each voice its pitch/detune  @ 126
      @contract  every voice sounding at a gate onset emits (none -> rest); the pattern loops from the window start; no lengthPpq -> inert  @ 127
  @fn vibrato(stream, host, params, ctx)  @ 154-174
      @contract  vibrato -> lane-1 pb-delta breakpoints in cents; sine of depth cents at 1/period QN  @ 151
      @contract  breakpoints at sine extrema, 'slow'-shaped; linear ramp-in over onset QN  @ 152
      @contract  returns to 0 (centre) at window end -- no residual bend on the channel  @ 153
  @fn interval(a, b)  @ 178-180
      -- Cents between two notes' realised pitches. The microtonal offset already rides
      -- in detune, so this is pure note arithmetic -- no temper needed.
  @fn slide(stream, host, params, ctx)  @ 185-215
      @contract  slide glide-in -> lane-1 pb-delta; slur to target over `over` QN; re-centres at end  @ 182
      @contract  target 'next' = interval to next same-lane note; 'fixed' = params.cents; pb-range clamps  @ 183
      @contract  no next note or unison target -> empty delta (channel untouched)  @ 184
  @fn autopan(stream, host, params, ctx)  @ 219-233
      @contract  auto-pan -> cc-delta breakpoints in cc steps; sine of depth steps at 1/period QN  @ 217
      @contract  extrema-only, 'slow'-shaped; anchored 0 at both ends so the channel re-centres  @ 218
  @fn curveAt(points, a)  @ 236-246
      -- Linear-interpolated normalized value at authored ppq `a`; points ascend in ppq, edges clamp flat.
  @fn lfo(stream, host, params, ctx)  @ 251-278
      @contract  lfo tiles a normalized curve at 1/period QN, mapping each val by centre + scale  @ 248
      @contract  emits absolute cc breakpoints (augment onto rest), clamped 0..127; dest cc1, no UI yet  @ 249
      @contract  each cycle stretches the body lengthPpq -> period ticks; both window edges seeded  @ 250
  @fn velPattern(stream, host, params, ctx)  @ 282-299
      @contract  velPattern rewrites stream-note velocities by a pattern; other fields carry verbatim  @ 280
      @contract  pattern steps per distinct onset (a chord shares one step) and cycles; vel clamps 1..127  @ 281

# Public API (generators.*)
  -- Generator registry
  -- Region park predicate + windows
  @api generators.parksNotes(region)  @ 409-415
      -- A region parks its covered chord iff it carries a note-dest kind: the chain's final note stream
      -- stands in for the members (ownership by dest, not mode). A husk (no kinds) parks nothing.
  @api generators.chainDestType(fx, target)  @ 419-425
      -- The fold mode a chain presents for one continuous target: replace if any stage targeting it
      -- replaces, else augment -- drives cross-chain layering (a later replace wins). see design/note-macros-v2.md § The fx chain
  @api generators.parkWindows(regions)  @ 430-451
      -- The single source for "what 4.5 parks over": a note window for a discrete-replace chord, a cc window
      -- per continuous cc target and a pb window per continuous pb target (both replace or augment).

